;; The town of Closure — the campaign's city.  Cities are ordinary
;; maps: the ZONE form marks the kind, LOCATION specials are the
;; buildings, TRAVEL specials are the gates and stairs (see
;; src/specials.lisp for the op vocabulary).  :GFX names the zone's
;; tile pack, resolved next to this map file (worlds/closure/gfx/ — the
;; city look: night sky, tan street); the cellar below
;; keeps the profile's default dungeon pack.

(zone :kind :city :title "Closure" :gfx "gfx/")

(special (4 5)
  (once (message "Welcome to Closure, last stop before the depths."
                 "Wolfgar's shoppe lies north-west; the tavern north-east.")))

(special (2 1)
  (location "Wolfgar's Arms & Armour" :shop
            :image "gfx/shop.iff"
            :stock (torch healing-potion short-sword war-axe broadsword
                    leather-armor chain-mail buckler)))

(special (6 1)
  (location "The Adventurer's Rest" :tavern :price 4 :down "cellar.map"
            :image "gfx/tavern.iff"))

;; The alley between the shop rows is safe by day — and not by night.
(special (4 1)
  (at-night (message "Footpads leap from the shadows!")
            (encounter ("footpad" "1d2"))))
